- Use `ng new my-angular-app` to create a new Angular project.
- Install NgRx using `npm install @ngrx/store`.
- Update Angular and NgRx to the latest versions for compatibility.
- Key config options include:
  - Store: Define reducers in `app.reducer.ts`.
  - Effects: Create effects in `app.effects.ts` for side effects.
  - Entities: Use `@ngrx/entity` for managing entity data efficiently.
- For MongoDB integration, use an API service to fetch and update data.
- Example of a reducer:
  ```typescript
  import { createReducer, on } from '@ngrx/store';
  import { loadUsersSuccess, loadUsersFailure } from './user.actions';

  export const initialState = {
    users: [],
    error: null,
  };

  const userReducer = createReducer(
    initialState,
    on(loadUsersSuccess, (state, { users }) => ({ ...state, users })),
    on(loadUsersFailure, (state, { error }) => ({ ...state, error }))
  );

  export function reducer(state, action) {
    return userReducer(state, action);
  }
  ```
- Example of an effect:
  ```typescript
  import { Injectable } from '@angular/core';
  import { Actions, createEffect, ofType } from '@ngrx/effects';
  import { mergeMap, map, catchError } from 'rxjs/operators';
  import { loadUsersSuccess, loadUsersFailure } from './user.actions';
  import { UserService } from '../services/user.service';

  @Injectable()
  export class UserEffects {
    constructor(private actions$: Actions, private userService: UserService) {}

    loadUsers$ = createEffect(() =>
      this.actions$.pipe(
        ofType(loadUsers),
        mergeMap(() =>
          this.userService.getUsers().pipe(
            map(users => loadUsersSuccess({ users })),
            catchError(error => of(loadUsersFailure({ error })))
          )
        )
      )
    );
  }
  ```
- Use Angular DevTools for debugging NgRx state.
